import { chmod, mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname } from "node:path";

export interface HostWrapperWriteResult {
  readonly path: string;
  readonly content: string;
  readonly changed: boolean;
}

export function renderHostWrapper(nodePath: string, hostEntrypointPath: string): string {
  return [
    "#!/bin/sh",
    "# Auto-generated by @koi/browser-ext install. Do not edit.",
    `exec "${nodePath}" "${hostEntrypointPath}" "$@"`,
    "",
  ].join("\n");
}

export async function writeHostWrapper(
  wrapperPath: string,
  nodePath: string,
  hostEntrypointPath: string,
): Promise<HostWrapperWriteResult> {
  const content = renderHostWrapper(nodePath, hostEntrypointPath);
  await mkdir(dirname(wrapperPath), { recursive: true, mode: 0o700 });

  let previous: string | null = null;
  try {
    previous = await readFile(wrapperPath, "utf8");
  } catch {}

  const changed = previous !== content;
  if (changed) {
    await writeFile(wrapperPath, content, { mode: 0o755 });
  }
  await chmod(wrapperPath, 0o755);

  return {
    path: wrapperPath,
    content,
    changed,
  };
}

export async function readBakedNodePath(wrapperPath: string): Promise<string | null> {
  try {
    const content = await readFile(wrapperPath, "utf8");
    const match = /^exec "([^"]+)" "[^"]+" "\$@"$/m.exec(content);
    return match?.[1] ?? null;
  } catch {
    return null;
  }
}
